import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User, Shield, Mail, Trash2, Edit, Save, X, Loader2, AlertCircle } from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editandoNome, setEditandoNome] = useState(false);
  const [novoNome, setNovoNome] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      setErroLocal(null);

      // 1. Pega o usuário da sessão atual
      const { data: { user }, error: authError } = await supabase.auth.getUser();

      if (authError || !user) {
        console.error("Erro de autenticação:", authError);
        setErroLocal("Sessão expirada. Faça login novamente.");
        return;
      }

      console.log("DEBUG: ID logado no App:", user.id);

      // 2. Busca o perfil na tabela pública
      const { data: meuPerfil, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .maybeSingle();

      if (profileError) {
        console.error("Erro ao buscar profile:", profileError);
        throw profileError;
      }

      console.log("DEBUG: Perfil retornado do Banco:", meuPerfil);

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');

        // 3. Se for proprietário, carrega a lista de usuários
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista, error: listError } = await supabase
            .from('profiles')
            .select('*')
            .order('nome', { ascending: true });
          
          if (!listError) setUsuarios(lista);
        }
      } else {
        console.warn("DEBUG: Nenhum registro encontrado na tabela 'profiles' para o ID:", user.id);
      }

    } catch (err) {
      setErroLocal("Erro ao carregar dados do servidor.");
    } finally {
      setLoading(false);
    }
  };

  const atualizarNome = async () => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ nome: novoNome })
        .eq('id', perfil.id);

      if (error) throw error;
      setPerfil({ ...perfil, nome: novoNome });
      setEditandoNome(false);
      alert("Nome atualizado com sucesso!");
    } catch (err) {
      alert("Erro ao atualizar nome.");
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (id === perfil.id) return alert("Você não pode excluir a si mesmo!");
    
    const confirma = window.confirm(`Deseja realmente excluir o usuário ${nome}?`);
    if (confirma) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
      } else {
        alert("Erro ao excluir: " + error.message);
      }
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '60vh', gap: '15px' }}>
        <Loader2 className="animate-spin" size={40} color="#4361ee" />
        <p style={{ color: '#64748b' }}>Sincronizando perfil...</p>
      </div>
    );
  }

  if (erroLocal || !perfil) {
    return (
      <div style={{ padding: '40px', textAlign: 'center' }}>
        <AlertCircle size={48} color="#ef4444" style={{ margin: '0 auto 20px' }} />
        <h3 style={{ color: '#0f172a' }}>Perfil não encontrado</h3>
        <p style={{ color: '#64748b', marginBottom: '20px' }}>{erroLocal || "Seu registro não foi localizado no banco de dados."}</p>
        <button onClick={() => window.location.reload()} style={btnReiniciar}>Tentar Novamente</button>
      </div>
    );
  }

  return (
    <div style={{ padding: '30px', maxWidth: '850px', margin: '0 auto' }}>
      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ fontSize: '1.8rem', fontWeight: 800, color: '#0f172a', display: 'flex', alignItems: 'center', gap: '12px' }}>
          <User size={32} color="#4361ee" /> Configurações de Perfil
        </h1>
      </header>

      {/* CARD DO MEU PERFIL */}
      <section style={cardStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1 }}>
            <label style={labelStyle}>Nome Completo</label>
            {editandoNome ? (
              <div style={{ display: 'flex', gap: '10px', marginTop: '5px' }}>
                <input 
                  value={novoNome} 
                  onChange={(e) => setNovoNome(e.target.value)}
                  style={inputStyle}
                  autoFocus
                />
                <button onClick={atualizarNome} style={saveBtnStyle}><Save size={18}/></button>
                <button onClick={() => setEditandoNome(false)} style={cancelBtnStyle}><X size={18}/></button>
              </div>
            ) : (
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <h2 style={{ margin: 0, fontSize: '1.4rem', color: '#1e293b' }}>{perfil.nome}</h2>
                <button onClick={() => setEditandoNome(true)} style={editBtnSmall}><Edit size={16} /></button>
              </div>
            )}
            
            <div style={{ marginTop: '15px', display: 'flex', gap: '20px' }}>
              <div>
                <label style={labelStyle}>E-mail</label>
                <p style={{ margin: '5px 0', color: '#64748b', display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <Mail size={16} /> {perfil.email}
                </p>
              </div>
              <div>
                <label style={labelStyle}>Nível de Acesso</label>
                <p style={{ margin: '5px 0' }}>
                  <span style={badgeStyle(perfil.tipo_usuario)}>
                    <Shield size={14} /> {perfil.tipo_usuario}
                  </span>
                </p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ÁREA DE GESTÃO (SÓ PARA PROPRIETÁRIO) */}
      {perfil.tipo_usuario === 'proprietario' && (
        <section style={{ marginTop: '40px' }}>
          <h3 style={{ fontSize: '1.2rem', fontWeight: 700, color: '#0f172a', marginBottom: '20px' }}>
            Gerenciamento de Usuários
          </h3>
          <div style={{ display: 'grid', gap: '12px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userItemStyle}>
                <div>
                  <div style={{ fontWeight: 700, color: '#1e293b' }}>{u.nome}</div>
                  <div style={{ fontSize: '0.85rem', color: '#94a3b8' }}>{u.email}</div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                  <span style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</span>
                  {u.id !== perfil.id && (
                    <button onClick={() => excluirUsuario(u.id, u.nome)} style={deleteBtnStyle}>
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS ---
const cardStyle = { backgroundColor: '#ffffff', padding: '30px', borderRadius: '24px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.05em' };
const inputStyle = { flex: 1, padding: '10px 15px', borderRadius: '12px', border: '2px solid #e2e8f0', fontSize: '1rem', outline: 'none', transition: 'border-color 0.2s' };
const saveBtnStyle = { background: '#22c55e', color: '#fff', border: 'none', borderRadius: '10px', padding: '10px', cursor: 'pointer' };
const cancelBtnStyle = { background: '#64748b', color: '#fff', border: 'none', borderRadius: '10px', padding: '10px', cursor: 'pointer' };
const editBtnSmall = { background: '#f1f5f9', color: '#64748b', border: 'none', borderRadius: '8px', padding: '6px', cursor: 'pointer', display: 'flex', alignItems: 'center' };
const userItemStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 20px', backgroundColor: '#fff', borderRadius: '16px', border: '1px solid #f1f5f9' };
const deleteBtnStyle = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '5px' };
const btnReiniciar = { background: '#4361ee', color: '#fff', border: 'none', padding: '12px 24px', borderRadius: '12px', fontWeight: 600, cursor: 'pointer' };
const badgeStyle = (tipo) => ({
  display: 'inline-flex', alignItems: 'center', gap: '5px', padding: '6px 12px', borderRadius: '10px', fontSize: '0.8rem', fontWeight: 700,
  backgroundColor: tipo === 'proprietario' ? '#4361ee15' : '#f1f5f9',
  color: tipo === 'proprietario' ? '#4361ee' : '#64748b',
  textTransform: 'uppercase'
});

export default Perfil;
